all_components = list(doc.deductions or []) + list(doc.earnings or [])

add_sal_names = set()
for c in all_components:
    if c.additional_salary:
        add_sal_names.add(c.additional_salary)

advance_names = set()
for aname in add_sal_names:
    ref = frappe.db.get_value('Additional Salary', aname, ['ref_doctype', 'ref_docname'], as_dict=True)
    if ref and ref.ref_doctype == 'Employee Advance' and ref.ref_docname:
        advance_names.add(ref.ref_docname)

for adv_name in advance_names:
    adv = frappe.get_doc('Employee Advance', adv_name)
    if adv.docstatus != 1:
        continue

    paid = float(adv.paid_amount or 0)
    if paid <= 0:
        continue

    linked = frappe.get_all('Additional Salary',
        filters={'ref_doctype': 'Employee Advance', 'ref_docname': adv_name, 'employee': adv.employee},
        fields=['name', 'salary_component']
    )

    total = 0
    seen = set()

    for ls in linked:
        slips = frappe.get_all('Salary Slip',
            filters={'employee': adv.employee, 'docstatus': 1},
            fields=['name']
        )
        for s in slips:
            sd = frappe.get_doc('Salary Slip', s.name)
            for comp in list(sd.deductions or []) + list(sd.earnings or []):
                if comp.salary_component == ls.salary_component and comp.additional_salary == ls.name:
                    key = str(s.name) + "-" + str(ls.name) + "-" + str(comp.idx)
                    if key not in seen:
                        seen.add(key)
                        total += abs(float(comp.amount or 0))

    remaining = max(0, paid - total)
    old_r = float(adv.custom_amount_received or 0)
    old_rem = float(adv.custom_remaining__amount or 0)

    if abs(old_r - total) > 0.01 or abs(old_rem - remaining) > 0.01:
        frappe.db.set_value('Employee Advance', adv_name, {
            'custom_amount_received': total,
            'custom_remaining__amount': remaining
        }, update_modified=False)

def execute():
    today = frappe.utils.nowdate()

    records = frappe.get_all(
        "Additional Salary",
        filters={
            "custom_disable_uncheck_date": today,
            "disabled": 1
        },
        fields=["name"]
    )

    if not records:
        return

    for record in records:
        try:
            doc = frappe.get_doc("Additional Salary", record.name)
            doc.disabled = 0
            doc.save(ignore_permissions=True)
        except Exception as e:
            frappe.log_error(
                message=f"Error updating Additional Salary {record.name}: {str(e)}",
                title="Auto-Uncheck Disabled Script"
            )

    frappe.db.commit()

execute()
